    "confirma_compra": {{ $('Identificar Acciones').item.json.output.confirma_compra }},
    "fin_de_conversacion": {{ $('Identificar Acciones').item.json.output.fin_de_conversacion }},
    "requiere_soporte": {{ $('Identificar Acciones').item.json.output.requiere_soporte }},
